/* ── Registry ──────────────────────────────────────────────────────────── */

const ICONS: Record<OsType, (p: IconProps) => JSX.Element> = {
  linux: TuxIcon,
  debian: DebianIcon,
  arch: ArchIcon,
  alpine: AlpineIcon,
  mint: MintIcon,
  kali: KaliIcon,
  macos: MacosIcon,
  windows: WindowsIcon,
};

export const OS_OPTIONS: { id: OsType; label: string }[] = [
  { id: 'linux', label: 'Linux' },
  { id: 'debian', label: 'Debian' },
  { id: 'arch', label: 'Arch' },
  { id: 'alpine', label: 'Alpine' },
  { id: 'mint', label: 'Mint' },
  { id: 'kali', label: 'Kali' },
  { id: 'macos', label: 'macOS' },
  { id: 'windows', label: 'Windows' },
];

const sans = '"Geist", "Inter", -apple-system, BlinkMacSystemFont, "SF Pro Text", system-ui, sans-serif';

export function OsIcon({
  os,
  size = 16,
  className = '',
}: {
  os?: OsType | string;
  size?: number;
  className?: string;
}) {
  const key = (os && os in ICONS ? os : 'linux') as OsType;
  const Cmp = ICONS[key];
  return <Cmp size={size} className={className} />;
}

/* ── Picker ────────────────────────────────────────────────────────────── */

export function OsPicker({
  value,
  onChange,
  size = 28,
}: {
  value: OsType;
  onChange: (os: OsType) => void;
  size?: number;
}) {
  const [open, setOpen] = useState(false);
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!open) return;
    const handle = (e: MouseEvent) => {
      if (ref.current && !ref.current.contains(e.target as Node)) setOpen(false);
    };
    const onKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') setOpen(false);
    };
    document.addEventListener('mousedown', handle);
    document.addEventListener('keydown', onKey);
    return () => {
      document.removeEventListener('mousedown', handle);
      document.removeEventListener('keydown', onKey);
    };
  }, [open]);

  const current = OS_OPTIONS.find((o) => o.id === value) ?? OS_OPTIONS[0];

  return (
    <div ref={ref} className="relative inline-flex">
      <motion.button
        type="button"
        onClick={() => setOpen((o) => !o)}
        whileTap={{ scale: 0.94 }}
        transition={{ duration: 0.08 }}
        title={`OS: ${current.label} — click to change`}
        className="flex items-center justify-center rounded-[6px] text-[#ededed] hover:text-white transition-colors"
        style={{
          width: size,
          height: size,
          background: '#0a0a0a',
          border: `1px solid ${open ? '#404040' : '#262626'}`,
        }}
      >
        <OsIcon os={value} size={Math.round(size * 0.55)} />
      </motion.button>

      <AnimatePresence>
        {open && (
          <motion.div
            initial={{ opacity: 0, scale: 0.96, y: -4 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.96, y: -4 }}
            transition={{ duration: 0.13, ease: [0.16, 1, 0.3, 1] }}
            className="absolute top-full left-0 mt-1.5 z-50 p-1.5 rounded-[8px]"
            style={{
              background: '#0e0e0e',
              border: '1px solid #262626',
              boxShadow: '0 12px 32px rgba(0,0,0,0.6), 0 0 0 1px rgba(255,255,255,0.02) inset',
              fontFamily: sans,
              minWidth: 168,
            }}
          >
            <div
              className="text-[9.5px] uppercase tracking-[0.08em] font-semibold text-[#666] px-1.5 pt-0.5 pb-1.5"
            >
              Operating system
            </div>
            <div className="grid grid-cols-4 gap-0.5">
              {OS_OPTIONS.map((opt) => {
                const active = opt.id === value;
                return (
                  <motion.button
                    key={opt.id}
                    type="button"
                    onClick={() => {
                      onChange(opt.id);
                      setOpen(false);
                    }}
                    whileTap={{ scale: 0.9 }}
                    transition={{ duration: 0.08 }}
                    title={opt.label}
                    className={`relative w-[34px] h-[34px] rounded-[5px] flex items-center justify-center transition-colors ${
                      active
                        ? 'text-white bg-[#1f1f1f]'
                        : 'text-[#888] hover:text-[#ededed] hover:bg-[#171717]'
                    }`}
                  >
                    <OsIcon os={opt.id} size={15} />
                    {active && (
                      <motion.span
                        layoutId="os-picker-active"
                        className="absolute inset-0 rounded-[5px] pointer-events-none"
                        style={{ border: '1px solid #404040' }}
                        transition={{ type: 'spring', stiffness: 500, damping: 40 }}
                      />
                    )}
                  </motion.button>
                );
              })}
            </div>
            <div
              className="text-[10.5px] text-[#888] px-1.5 pt-1.5 pb-0.5 truncate"
              style={{ fontFamily: sans }}
            >
              {current.label}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}